#include<bits/stdc++.h>
using namespace std;
int n,m,k=0,sum=0,fa[5005];
struct edge
{
    int u,v,w;
};
edge e[200005],mst[200005];
bool cmp(edge a,edge b)
{
    return a.w<b.w;
}
int Find(int x)
{
    if(fa[x]==x) return x;
    else return fa[x]=Find(fa[x]);
}
void Union(int a,int b)
{
    int faa=Find(a);
    int fab=Find(b);
    if(faa!=fab) fa[fab]=faa;
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++) fa[i]=i;
    for(int i=0;i<m;i++) cin>>e[i].u>>e[i].v>>e[i].w;
    sort(e,e+m,cmp);
    for(int i=0;i<m;i++)
    {
        if(Find(e[i].u)!=Find(e[i].v))
        {
            mst[++k]=e[i];
            sum+=e[i].w;
            Union(e[i].u,e[i].v);
            if(k==n-1) break;
        }
    }
    if(k<n-1) cout<<"orz";
    else cout<<sum;
    return 0;
}
